// enhanced_gguf_loader.cpp - Integrate validation & recovery
#include "enhanced_gguf_loader.h"
#include "gguf_tensor_validator.h"
#include <QFile>
#include <QDataStream>
#include <iostream>

class EnhancedGGUFLoader : public QObject {
    Q_OBJECT
    
private:
    std::unique_ptr<GGUFFensorValidator> tensorValidator;
    QHash<QString, QByteArray> tensorCache;
    QHash<QString, TensorValidationResult> validationResults;
    bool enableValidation = true;
    bool enableRecovery = true;
    int recoveryAttemptLimit = 3;

public:
    EnhancedGGUFLoader(QObject* parent = nullptr) : QObject(parent) {
        tensorValidator = std::make_unique<GGUFFensorValidator>();
        
        // Connect validation signals
        connect(tensorValidator.get(), &GGUFFensorValidator::tensorValidationFailed,
                this, &EnhancedGGUFLoader::onTensorValidationFailed);
        
        connect(tensorValidator.get(), &GGUFFensorValidator::tensorRecovered,
                this, &EnhancedGGUFLoader::onTensorRecovered);
        
        std::cout << "[EnhancedGGUFLoader] Initialized with tensor validation & recovery" << std::endl;
    }
    
    bool loadModelWithValidation(const QString& modelPath, bool cpuOnly = false) {
        std::cout << "[EnhancedGGUFLoader] Loading model with validation: " << modelPath.toStdString() << std::endl;
        
        try {
            // Open GGUF file
            QFile file(modelPath);
            if (!file.open(QIODevice::ReadOnly)) {
                throw std::runtime_error("Failed to open model file");
            }
            
            QDataStream stream(&file);
            stream.setByteOrder(QDataStream::LittleEndian);
            
            // Read and validate GGUF header
            GGUFHeader header = readGGUFHeader(stream);
            if (!validateGGUFHeader(header)) {
                throw std::runtime_error("Invalid GGUF header");
            }
            
            // Read metadata
            QHash<QString, QVariant> metadata = readGGUFMetadata(stream, header.metadataCount);
            
            // Read and validate tensors
            QHash<QString, GGUFTensorInfo> tensorInfos = readTensorInfos(stream, header.tensorCount);
            
            int validTensors = 0;
            int recoveredTensors = 0;
            int failedTensors = 0;
            
            for (const auto& [tensorName, tensorInfo] : tensorInfos) {
                std::cout << "[EnhancedGGUFLoader] Processing tensor: " << tensorName.toStdString() << std::endl;
                
                // Read tensor data
                QByteArray tensorData = readTensorData(stream, tensorInfo);
                
                // Validate tensor
                if (enableValidation) {
                    TensorValidationResult validation = tensorValidator->validateTensor(
                        tensorName, tensorData, tensorInfo.size, tensorInfo.ggmlType
                    );
                    
                    validationResults[tensorName] = validation;
                    
                    if (!validation.isValid) {
                        std::cerr << "[EnhancedGGUFLoader] Tensor validation failed: " 
                                  << tensorName.toStdString() << " - " << validation.errorMessage.toStdString() << std::endl;
                        
                        // Attempt recovery
                        if (enableRecovery && validation.recommendedAction == "attempt_recovery") {
                            std::cout << "[EnhancedGGUFLoader] Attempting recovery for: " << tensorName.toStdString() << std::endl;
                            
                            QByteArray recoveredData = tensorValidator->recoverTensorData(
                                tensorName, tensorData, tensorInfo.size, metadata
                            );
                            
                            if (!recoveredData.isEmpty()) {
                                tensorCache[tensorName] = recoveredData;
                                recoveredTensors++;
                                std::cout << "[EnhancedGGUFLoader] Tensor recovered successfully: " << tensorName.toStdString() << std::endl;
                            } else {
                                failedTensors++;
                                std::cerr << "[EnhancedGGUFLoader] Tensor recovery failed: " << tensorName.toStdString() << std::endl;
                            }
                        } else {
                            failedTensors++;
                        }
                    } else {
                        tensorCache[tensorName] = tensorData;
                        validTensors++;
                    }
                } else {
                    // Skip validation, just cache the data
                    tensorCache[tensorName] = tensorData;
                    validTensors++;
                }
            }
            
            file.close();
            
            // Generate validation report
            QJsonObject validationReport;
            validationReport["total_tensors"] = tensorInfos.size();
            validationReport["valid_tensors"] = validTensors;
            validationReport["recovered_tensors"] = recoveredTensors;
            validationReport["failed_tensors"] = failedTensors;
            validationReport["success_rate"] = static_cast<double>(validTensors + recoveredTensors) / tensorInfos.size();
            
            std::cout << "[EnhancedGGUFLoader] Validation report: " << QJsonDocument(validationReport).toJson(QJsonDocument::Compact).toStdString() << std::endl;
            
            // Check if we have enough valid tensors to proceed
            double successRate = static_cast<double>(validTensors + recoveredTensors) / tensorInfos.size();
            if (successRate < 0.8) { // Require at least 80% success rate
                throw std::runtime_error(QString("Insufficient tensor validation success rate: %1%").arg(successRate * 100).toStdString());
            }
            
            std::cout << "[EnhancedGGUFLoader] Model loaded successfully with validation" << std::endl;
            return true;
            
        } catch (const std::exception& e) {
            std::cerr << "[EnhancedGGUFLoader] Failed to load model: " << e.what() << std::endl;
            return false;
        }
    }
    
    QByteArray recoverCorruptedTensor(const QString& tensorName,
                                     const QByteArray& corruptedData,
                                     qint64 expectedSize,
                                     const QHash<QString, QByteArray>& nearbyTensors) {
        std::cout << "[EnhancedGGUFLoader] Recovering corrupted tensor: " << tensorName.toStdString() << std::endl;
        
        // Try multiple recovery strategies
        QVector<std::function<QByteArray()>> recoveryAttempts = {
            [&]() { return tensorValidator->generateDefaultTensor(tensorName, expectedSize, 0); },
            [&]() { return tensorValidator->interpolateMissingTensor(tensorName, nearbyTensors, expectedData); },
            [&]() { return QByteArray(expectedSize, 0); } // Final fallback: zero-filled
        };
        
        for (int attempt = 0; attempt < recoveryAttempts.size(); ++attempt) {
            std::cout << "[EnhancedGGUFLoader] Recovery attempt " << (attempt + 1) << " for " << tensorName.toStdString() << std::endl;
            
            QByteArray recoveredData = recoveryAttempts[attempt]();
            if (!recoveredData.isEmpty() && recoveredData.size() == expectedSize) {
                // Validate the recovered data
                TensorValidationResult validation = tensorValidator->validateTensor(
                    tensorName, recoveredData, expectedSize, 0
                );
                
                if (validation.isValid) {
                    std::cout << "[EnhancedGGUFLoader] Recovery successful on attempt " << (attempt + 1) << std::endl;
                    return recoveredData;
                }
            }
        }
        
        std::cerr << "[EnhancedGGUFLoader] All recovery attempts failed for: " << tensorName.toStdString() << std::endl;
        return QByteArray();
    }

private slots:
    void onTensorValidationFailed(const TensorValidationResult& result) {
        std::cerr << "[EnhancedGGUFLoader] Tensor validation failed: " << result.tensorName.toStdString() 
