VocabSizeDetection GGUFVocabResolver::detectVocabSize(const QHash<QString, QVariant>& metadata,
                                                     const QString& modelPath) {
    std::cout << "[GGUFVocabResolver] Detecting vocab size from " << metadata.size() << " metadata entries" << std::endl;
    
    // Step 1: Determine model family
    QString modelFamily = determineModelFamily(metadata, modelPath);
    std::cout << "[GGUFVocabResolver] Detected model family: " << modelFamily.toStdString() << std::endl;
    
    // Step 2: Try family-specific detection
    VocabSizeDetection detection;
    
    if (modelFamily == "llama" || modelFamily.contains("llama")) {
        detection = detectLlamaVocabSize(metadata);
    } else if (modelFamily == "gpt" || modelFamily.contains("gpt")) {
        detection = detectGPTVocabSize(metadata);
    } else if (modelFamily == "t5" || modelFamily.contains("t5")) {
        detection = detectT5VocabSize(metadata);
    } else if (modelFamily == "bert" || modelFamily.contains("bert")) {
        detection = detectBertVocabSize(metadata);
    } else if (modelFamily == "claude" || modelFamily.contains("claude")) {
        detection = detectClaudeVocabSize(metadata);
    } else {
        detection = detectGenericVocabSize(metadata);
    }
    
    // Step 3: Validate and correct the detection
    detection = validateAndCorrect(detection);
    
    // Step 4: Handle special cases
    if (modelProfiles.contains(modelFamily) && modelProfiles[modelFamily].requiresSpecialHandling) {
        qint64 correctedSize = handleSpecialCases(modelFamily, metadata);
        if (correctedSize != detection.detectedSize) {
            detection.detectedSize = correctedSize;
            detection.detectionMethod += " (special_case_corrected)";
            emit specialCaseHandled(modelFamily, correctedSize);
        }
    }
    
    emit vocabSizeDetected(detection);
    
    std::cout << "[GGUFVocabResolver] Final detection: " << detection.detectedSize 
              << " (method: " << detection.detectionMethod.toStdString() 
              << ", confidence: " << detection.isConfident << ")" << std::endl;
    
    return detection;
}

VocabSizeDetection GGUFVocabResolver::detectLlamaVocabSize(const QHash<QString, QVariant>& metadata) {
    QVector<QString> evidence = collectVocabEvidence(metadata);
    
    // Primary method: Look for llama.vocab_size
    if (metadata.contains("llama.vocab_size")) {
        qint64 size = metadata["llama.vocab_size"].toLongLong();
        if (isVocabSizeReasonable(size, "llama")) {
            return createDetection("llama.vocab_size", size, true, {"llama.vocab_size"});
        }
    }
    
    // Secondary method: Look for generic vocab_size
    if (metadata.contains("vocab_size")) {
        qint64 size = metadata["vocab_size"].toLongLong();
        if (isVocabSizeReasonable(size, "llama")) {
            return createDetection("vocab_size", size, true, {"vocab_size"});
        }
    }
    
    // Tertiary method: Look for n_vocab
    if (metadata.contains("n_vocab")) {
        qint64 size = metadata["n_vocab"].toLongLong();
        if (isVocabSizeReasonable(size, "llama")) {
            return createDetection("n_vocab", size, true, {"n_vocab"});
    }
    
    // Fallback method: Detect from tensor dimensions
    return detectFromTensorDimensions(metadata);
}

VocabSizeDetection GGUFVocabResolver::detectFromTensorDimensions(const QHash<QString, QVariant>& metadata) {
    // Look for embedding tensor dimensions
    QVector<QString> embeddingTensorPatterns = {
        "token_embedding.weight", "embed_tokens.weight", "wte.weight",
        "model.embed_tokens.weight", "transformer.wte.weight"
    };
    
    for (const QString& pattern : embeddingTensorPatterns) {
        QString key = QString("tensor.%1.shape").arg(pattern);
        if (metadata.contains(key)) {
            QVariant shapeData = metadata[key];
            if (shapeData.typeId() == QMetaType::QVariantList) {
                QVariantList shape = shapeData.toList();
                if (shape.size() >= 2) {
                    qint64 vocabSize = shape[0].toLongLong();
                    if (isVocabSizeReasonable(vocabSize)) {
                        return createDetection("tensor_dimensions", vocabSize, true, {key});
                    }
                }
            }
        }
    }
    
    // Look for output tensor dimensions
    QVector<QString> outputTensorPatterns = {
        "output.weight", "lm_head.weight", "transformer.output.weight"
    };
    
    for (const QString& pattern : outputTensorPatterns) {
        QString key = QString("tensor.%1.shape").arg(pattern);
        if (metadata.contains(key)) {
            QVariant shapeData = metadata[key];
            if (shapeData.typeId() == QMetaType::QVariantList) {
                QVariantList shape = shapeData.toList();
                if (shape.size() >= 2) {
                    qint64 vocabSize = shape[0].toLongLong();
                    if (isVocabSizeReasonable(vocabSize)) {
                        return createDetection("output_tensor_dimensions", vocabSize, true, {key});
                    }
                }
            }
        }
    }
    
    // Ultimate fallback: TinyLlama specific detection
    return detectTinyLlamaSpecific(metadata);
}

VocabSizeDetection GGUFVocabResolver::detectTinyLlamaSpecific(const QHash<QString, QVariant>& metadata) {
    // TinyLlama specific detection logic
    QVector<QString> tinyLlamaEvidence = collectVocabEvidence(metadata);
    
    // Look for evidence of TinyLlama
    bool isTinyLlama = false;
    for (const QString& evidence : tinyLlamaEvidence) {
        if (evidence.contains("tiny") || evidence.contains("1.1b") || evidence.contains("1b")) {
            isTinyLlama = true;
            break;
        }
    }
    
    if (isTinyLlama) {
        // TinyLlama uses standard Llama vocab (32000)
        return createDetection("tinyllama_specific", 32000, true, tinyLlamaEvidence);
    }
    
    // Final fallback: use reasonable default
    return createDetection("reasonable_default", 32000, false, {"default_assumption"});
}

bool GGUFVocabResolver::isVocabSizeReasonable(qint64 vocabSize, const QString& modelFamily) const {
    // Apply sanity bounds
    if (vocabSize < minVocabSize || vocabSize > maxVocabSize) {
        return false;
    }
    
    // Model-specific reasonable ranges
    if (!modelFamily.isEmpty() && modelProfiles.contains(modelFamily)) {
        qint64 expected = modelProfiles[modelFamily].expectedVocabSize;
        qint64 tolerance = expected * 0.1; // 10% tolerance
        return (vocabSize >= expected - tolerance) && (vocabSize <= expected + tolerance);
    }
    
    // Generic reasonable ranges
    if (vocabSize > 50000 && vocabSize < 200000) return true; // Standard range
    if (vocabSize > 200000 && vocabSize < 300000) return true; // Large vocab range
    if (vocabSize > 300000 && vocabSize < 500000) return true; // Very large vocab range
    
    return false;
}

qint64 GGUFVocabResolver::applySanityBounds(qint64 detectedSize) {
    qint64 originalSize = detectedSize;
    
    // Apply upper bound
    if (detectedSize > maxVocabSize) {
        detectedSize = maxVocabSize;
        emit sanityCheckApplied(originalSize, detectedSize);
        std::cout << "[GGUFVocabResolver] Sanity check applied: " << originalSize 
                  << " -> " << detectedSize << std::endl;
    }
    
    // Apply lower bound
    if (detectedSize < minVocabSize) {
        detectedSize = minVocabSize;
        emit sanityCheckApplied(originalSize, detectedSize);
        std::cout << "[GGUFVocabResolver] Sanity check applied: " << originalSize 
                  << " -> " << detectedSize << std::endl;
    }
    
    return detectedSize;
}

VocabSizeDetection GGUFVocabResolver::validateAndCorrect(VocabSizeDetection detection) {
    // Apply sanity bounds
    detection.detectedSize = applySanityBounds(detection.detectedSize);
    
    // Check confidence
    detection.isConfident = calculateDetectionConfidence(detection) >= mediumConfidenceThreshold;
    
    // If low confidence, try to improve
    if (!detection.isConfident) {
        VocabSizeDetection improved = improveConfidence(detection);
        if (improved.isConfident) {
            return improved;
        }
    }
    
    return detection;
}

