QString GGUFVocabResolver::determineModelFamily(const QHash<QString, QVariant>& metadata,
                                               const QString& modelPath) const {
    // Method 1: Check metadata for model family indicators
    QVector<QString> familyIndicators = {
        "general.architecture", "llama.context_length", "gpt.context_length",
        "t5.context_length", "bert.context_length", "mistral.context_length",
        "general.name", "general.description", "general.basename"
    };
    
    for (const QString& indicator : familyIndicators) {
        if (metadata.contains(indicator)) {
            QString value = metadata[indicator].toString().toLower();
            if (value.contains("llama")) return "llama";
            if (value.contains("gpt")) return "gpt";
            if (value.contains("t5")) return "t5";
            if (value.contains("bert")) return "bert";
            if (value.contains("mistral")) return "mistral";
            if (value.contains("claude")) return "claude";
            if (value.contains("gemma")) return "gemma";
            if (value.contains("tiny")) return "tiny";
        }
    }
    
    // Method 2: Check model path for family indicators
    if (!modelPath.isEmpty()) {
        QString pathLower = modelPath.toLower();
        if (pathLower.contains("tinyllama") || pathLower.contains("tiny")) return "tiny";
        if (pathLower.contains("llama")) return "llama";
        if (pathLower.contains("gpt")) return "gpt";
        if (pathLower.contains("mistral")) return "mistral";
        if (pathLower.contains("claude")) return "claude";
        if (pathLower.contains("gemma")) return "gemma";
    }
    
    // Method 3: Check tensor names for family indicators
    for (auto it = metadata.begin(); it != metadata.end(); ++it) {
        QString key = it.key().toLower();
        if (key.contains("llama")) return "llama";
        if (key.contains("gpt")) return "gpt";
        if (key.contains("mistral")) return "mistral";
        if (key.contains("claude")) return "claude";
    }
    
    // Default: detect from tensor patterns
    return detectFromTensorPatterns(metadata);
}

qint64 GGUFVocabResolver::handleSpecialCases(const QString& modelFamily,
                                            const QHash<QString, QVariant>& metadata) {
    // Handle TinyLlama specifically
    if (modelFamily == "tiny" || modelFamily.contains("tiny")) {
        // TinyLlama should use standard 32000 vocab despite what metadata says
        std::cout << "[GGUFVocabResolver] Special case: TinyLlama detected, using standard vocab size" << std::endl;
        return 32000;
    }
    
    // Handle cases where metadata is clearly wrong
    if (metadata.contains("vocab_size")) {
        qint64 claimedSize = metadata["vocab_size"].toLongLong();
        if (claimedSize > 1000000 && modelFamily == "llama") {
            // This is likely corrupted metadata - use reasonable default
            std::cout << "[GGUFVocabResolver] Special case: Correcting corrupted vocab size " << claimedSize << " -> 32000" << std::endl;
            return 32000;
        }
    }
    
    return -1; // No special handling needed
}

VocabSizeDetection GGUFVocabResolver::createDetection(const QString& method,
                                                     qint64 size,
                                                     bool confident,
                                                     const QVector<QString>& evidence) {
    VocabSizeDetection detection;
    detection.detectionMethod = method;
    detection.detectedSize = size;
    detection.isConfident = confident;
    detection.evidenceKeys = evidence;
    detection.metadata["confidence_score"] = confident ? 0.95 : 0.75;
    detection.metadata["evidence_count"] = evidence.size();
    
    return detection;
}
