                );
                
                if (validation.isValid) {
                    std::cout << "[EnhancedGGUFLoader] Recovery successful on attempt " << (attempt + 1) << std::endl;
                    return recoveredData;
                }
            }
        }
        
        std::cerr << "[EnhancedGGUFLoader] All recovery attempts failed for: " << tensorName.toStdString() << std::endl;
        return QByteArray();
    }

